import re

filepath = 'curriculum/l2-uk-en/a2/asking-for-directions.md'
with open(filepath, 'r', encoding='utf-8') as f:
    content = f.read()

# 1. Participle
content = content.replace('пройдений', 'новий')

# 2. Transliteration
content = content.replace('Особа (Person)', 'Особа')

# 3. Add more English to drop immersion < 90%.
english_scaffolding_3 = """
> [!note] Grammar Scaffolding: Asking Questions and Politeness
> When asking for directions in Ukraine, politeness goes a long way. You should always start with a polite opener like "Перепрошую" (Excuse me) or "Вибачте" (Sorry). Then, you can ask your question. The most common ways to ask are using the phrases "Як дійти до..." (How to get to... on foot) or "Як доїхати до..." (How to get to... by transport). Both of these require the preposition "до" followed by the Genitive case.
> 
> Another excellent way to ask is "Де знаходиться..." (Where is located...). This is followed by the Nominative case, making it very easy for beginners. For example, "Де знаходиться аптека?" (Where is the pharmacy located?). When people answer you, they will give instructions using the imperative mood (Наказовий спосіб), which gives commands or directions. You will hear words like "ідіть" (go/walk), "поверніть" (turn), or "перейдіть" (cross). These are the formal/plural imperative forms, which show respect. Paying attention to these verb forms will make following directions much easier.
"""
content = content.replace('### Пересадки та кінцеві зупинки', english_scaffolding_3 + '\\n### Пересадки та кінцеві зупинки')

